package com.archivenexus.backend.ai;
import com.archivenexus.backend.ai.ManufacturingAiModels.*;import com.archivenexus.backend.domain.DomainModels.LogisticsShipment;import com.archivenexus.backend.service.NexusStateService;import org.springframework.stereotype.Component;import java.util.*;
@Component public class LogisticsAgent implements ManufacturingAgent{
 private final NexusStateService nexus;public LogisticsAgent(NexusStateService nexus){this.nexus=nexus;}
 public String getName(){return "LogisticsAgent";}public boolean supports(Intent intent){return intent==Intent.LOGISTICS;}public int getPriority(){return 50;}
 public AgentResult analyze(AgentContext context){long started=System.nanoTime();List<LogisticsShipment> rows=nexus.shipments().stream().filter(s->context.selectedFactoryId()==null||context.selectedFactoryId().equals(s.factoryId())).toList();if(rows.isEmpty())return new AgentResult(getName(),Intent.LOGISTICS,"판단할 물류 데이터가 부족함",List.of(),List.of(),0,elapsed(started),AgentExecutionStatus.INSUFFICIENT_DATA,null,false);long delayed=rows.stream().filter(s->"DELAYED".equalsIgnoreCase(s.status())).count();int maxPriority=rows.stream().mapToInt(LogisticsShipment::priority).max().orElse(0);List<AgentEvidence> evidence=List.of(new AgentEvidence("LOGISTICS","지연 출하",delayed+"/"+rows.size(),"logisticsShipments"),new AgentEvidence("LOGISTICS","최고 출하 우선순위",String.valueOf(maxPriority),"logisticsShipments"));List<String> actions=delayed>0?List.of("지연 출하의 재고 할당과 대체 운송 계획을 PM 승인 대상으로 검토하세요."):List.of();return new AgentResult(getName(),Intent.LOGISTICS,delayed>0?"출하 지연 "+delayed+"건이 확인되었습니다.":"현재 출하 지연이 확인되지 않았습니다.",evidence,actions,delayed>0?0.9:0.82,elapsed(started),AgentExecutionStatus.COMPLETED,null,delayed>0);}
 private long elapsed(long started){return(System.nanoTime()-started)/1_000_000;}
}
